INSERT INTO `post` (`id`, `created_at`, `created_by`, `description`, `detail`, `image`, `slug`, `status`, `title`, `topic_id`, `isDelete`) VALUES
(1, '2025-03-22 21:11:09.000000', 1, 'Thông tin về iPhone mới nhất của Apple', '<p>Apple vừa ra mắt iPhone mới với nhiều t&iacute;nh năng đột ph&aacute;. Sản phẩm n&agrave;y được kỳ vọng sẽ tạo ra l&agrave;n s&oacute;ng mới trong thị trường smartphone.</p>\n<p><img src=\"data:image/png;base64,\"></p>\n<p>Với chip mới, camera được n&acirc;ng cấp v&agrave; pin c&oacute; thời lượng d&agrave;i hơn, iPhone mới đ&atilde; nhận được nhiều đ&aacute;nh gi&aacute; t&iacute;ch cực từ c&aacute;c chuy&ecirc;n gia c&ocirc;ng nghệ.</p>\n<p><img src=\"data:image/png;base64,\"></p>', 'image1.png', 'apple-ra-mat-iphone-moi', 1, 'Apple ra mắt iPhone mới', 1, 0);
INSERT INTO `post` (`id`, `created_at`, `created_by`, `description`, `detail`, `image`, `slug`, `status`, `title`, `topic_id`, `isDelete`) VALUES
(2, '2025-03-24 20:31:58.000000', 1, 'Thông tin về iPhone mới nhất của Apple', 'Ấn tượng ban đầu về iPhone 15 Pro Giống như người anh Pro Max, 15 Pro chỉ đi kèm duy nhất một phụ kiện là cáp USB-C. Không ít khách hàng cho rằng họ xứng đáng nhận được nhiều hơn là một dây sạc. Tuy nhiên, thay đổi trên đã mang đến những tác động tích cực cho cả nhà sản xuất và môi trường. Cầm điện thoại trên tay, điều đầu tiên gây ấn tượng là trọng lượng khá nhẹ. iPhone 15 Pro nhẹ hơn phiên bản tiền nhiệm khoảng 19 gram. Thiết bị được các kỹ sư Apple dành nhiều giờ đồng hồ để hoàn thiện với chất liệu titan cao cấp.Thay vì sở hữu vẻ ngoài bóng loáng, cạnh viền như dao cạo, 15 Pro mới vẫn giữa nguyên thiết kế thời thượng nhưng tinh tế và linh hoạt hơn. Các đường cong nhẹ, bo cạnh mềm mại kết hợp lớp sơn mờ chống bám dính mồ hôi giúp người dùng cầm nắm thoải mái, dễ dàng.Bên cạnh đó, nút Hành động không còn là một công cụ đơn giản để bật/tắt tiếng đơn giản, chi tiết mới tích hợp nhiều tác vụ thú vị và hấp dẫn.Chất lượng hình ảnh và âm thanh trên iPhone 15 Pro gần như không có điểm trừ. Màn hình Super Retina OLED, đi kèm tần số quét 120Hz, và độ sáng tối đa lên đến 2000 nits hứa hẹn cho trải nghiệm xem phim, lướt web giải trí đỉnh cao. Mặc dù không được trang bị ống kính tiềm vọng như 15 Pro Max nhưng những gì bạn nhận được ở iPhone 15 Pro là điều tốt nhất trong phân khúc giá. Các tín đồ công nghệ đã dành lời khen cho khả năng nhiếp ảnh cũng như tỏ ra thích thú với độ dài tiêu cự hợp lý trên 15 Pro. Hiệu năng phần cứng vẫn luôn được đông đảo dân công nghệ quan tâm. Chip A17 Pro dường như là nâng cấp mà Apple tạo ra sự khác biệt giữa dòng sản phẩm thông thường và dòng Pro cao cấp hơn. Cấu hình khủng của 15 Pro có thể cân đẹp các tác vụ đòi hỏi khả năng xử lý tốt. ', 'image2.png', 'iphone-15-pro', 2, 'Đập hộp iPhone 15 Pro', 1, 0),
(3, '2025-03-24 20:50:28.000000', 1, 'Thông tin về iPhone mới nhất của Apple', 'Thông tin chi tiết về iPhone 15 SeriesViệc tăng giá này có thể được quy cho việc giới thiệu một công nghệ titan mới và cải tiến trong phần cứng máy ảnh. Tuy nhiên, các mẫu iPhone 15 và iPhone 15 Plus cơ sở dự kiến sẽ duy trì các thẻ giá hiện tại của chúng.Theo một báo cáo của nhà phân tích Luke Lin của Digitimes, sẽ có tăng giá đáng kể cho iPhone 15 Pro và iPhone 15 Pro Max so với sản phẩm tiền nhiệm.Điều chỉnh giá này có khả năng chiếm một số cải tiến phần cứng được đồn đại, bao gồm cả việc chuyển từ thép không gỉ sang khung Titanium cho iPhone 15 Pro và giới thiệu hệ thống camera Periscope trên iPhone 15 Pro Max, cho phép tăng khả năng thu phóng quang học lên tới 5-6x. Tuy nhiên, giá cho các mẫu iPhone 15 và iPhone 15 Plus tiêu chuẩn dự kiến sẽ không thay đổi.Nếu việc tăng giá này có hiệu lực, iPhone 15 Pro Max có thể trở thành iPhone đắt nhất từng được phát hành. Hiện tại, iPhone 14 Pro Max nắm giữ tiêu đề đó. IPhone 14 Pro và iPhone 14 Pro Max đã được ra mắt vào năm ngoái với giá khởi điểm lần lượt là $999 và $1,099.Mặc dù giá mới chính xác không được chỉ định, một báo cáo trước đây cho thấy iPhone 15 Pro có thể bắt đầu ở mức 1.099$, sẽ nhiều hơn 100$ so với người tiền nhiệm, trong khi iPhone 15 Pro Max có thể bắt đầu ở mức 1,299$, tăng 200$ so với iPhone 14 Pro Max.', 'image3.png', 'mau-iphone-titan', 1, 'Các mẫu iPhone 15 Pro sẽ tăng giá do trang bị khung máy bằng titan', 1, 0),
(4, '2025-03-24 20:53:55.000000', 1, 'Thông tin về iPhone mới nhất của Apple', '<p>3 điểm nổi bật nhất của Claude AI.1, Cho ph&eacute;p upload t&agrave;i liệu PDF, TXT, EXCEL l&ecirc;n hệ thống để AI t&oacute;m tắt, ph&acirc;n t&iacute;ch đưa ra đ&aacute;nh gi&aacute; dựa tr&ecirc;n t&agrave;i liệu đ&oacute;. Do vậy nội dung s&aacute;ng tạo theo y&ecirc;u cầu rất tốt.2, Token đầu ra của con AI n&agrave;y l&ecirc;n đến 100K (75K chữ) trong khi chatgpt chỉ tối đa 8K token 1 lần (~6k chữ).3, Trả lời th&ocirc;ng minh v&agrave; c&oacute; chiều s&acirc;u hơn chatgptClaude AI l&agrave; g&igrave;?Claude AI, do Anthropic ph&aacute;t triển, l&agrave; một chatbot AI c&oacute; t&iacute;nh năng v&agrave; độ tin cậy cao. Ứng dụng n&agrave;y đ&atilde; được huấn luyện tr&ecirc;n một lượng dữ liệu lớn bao gồm cả văn bản v&agrave; m&atilde; nguồn. Claude AI c&oacute; khả năng tạo ra nội dung văn bản, dịch thuật, s&aacute;ng tạo c&aacute;c loại nội dung kh&aacute;c nhau, t&oacute;m tắt nội dung v&agrave; trả lời c&aacute;c c&acirc;u hỏi m&agrave; bạn đặt ra. Lưu &yacute; rằng nội dung của bạn phải viết bằng tiếng Việt, v&igrave; đối tượng người d&ugrave;ng của Claude AI được xem l&agrave; người Việt Nam.C&aacute;ch đăng k&yacute; t&agrave;i khoản Claude AITrước khi t&igrave;m hiểu về c&aacute;ch sử dụng Claude Ai, ch&uacute;ng ta sẽ c&ugrave;ng đi t&igrave;m hiểu về c&aacute;ch đăng k&yacute; ứng dụng n&agrave;y trước. Claude AI hiện tại chỉ hỗ trợ 2 khu vực l&agrave; Hoa Kỳ v&agrave; Vương quốc Anh. Do đ&oacute;, để thực hiện c&aacute;ch đăng k&yacute; sử dụng Claude AI, bạn sẽ cần thay đổi VPN của m&igrave;nh về một trong hai khu vực tr&ecirc;n.Link đăng k&yacute;:https://claude.ai/login Sử dụng email để lấy code đăng nhập</p>', 'image4.png', 'AI', 1, 'Thủ thuật đăng ký Claude Ai và cách dùng hiệu quả', 2, 0),
(5, '2025-03-24 20:56:55.000000', 1, 'Thông tin về iPhone mới nhất của Apple', '<p>Th&ocirc;ng tin chi tiết về Galaxy A55 5G Một trong những điểm nổi bật ch&iacute;nh của Galaxy A55 l&agrave; việc sử dụng chip Exynos 1480 Soc của Samsung. Chipset n&agrave;y dự kiến sẽ l&agrave; một cải tiến đ&aacute;ng kể so với những người tiền nhiệm của n&oacute;, thậm ch&iacute; c&oacute; thể kết hợp GPU c&oacute; nguồn gốc AMD. Sự thay đổi trong c&ocirc;ng suất xử l&yacute; n&agrave;y c&oacute; thể cung cấp hiệu suất n&acirc;ng cao cho người d&ugrave;ng.Một t&iacute;nh năng đ&aacute;ng ch&uacute; &yacute; kh&aacute;c l&agrave; cảm biến camera ph&iacute;a sau ch&iacute;nh 50 megapixel được đồn đại, đầy hứa hẹn khả năng chụp ảnh được cải thiện so với người tiền nhiệm của n&oacute;. Mặc d&ugrave; một th&ocirc;ng b&aacute;o ch&iacute;nh thức đang chờ xử l&yacute;, nhưng Samsung c&oacute; thể tiết lộ Galaxy A55 v&agrave;o th&aacute;ng 3 của năm sắp tới.Sản phẩm c&oacute; nhiều t&ugrave;y chọn m&agrave;u sắc kh&aacute;c nhau v&agrave; cung cấp một bộ t&iacute;nh năng chắc chắn, bao gồm m&agrave;n h&igrave;nh si&ecirc;u AMOLED 120Hz, camera ba mặt sau v&agrave; pin 5.000mAh.Khi Samsung tiếp tục đổi mới trong d&ograve;ng điện thoại th&ocirc;ng minh tầm trung, người ti&ecirc;u d&ugrave;ng c&oacute; thể dự đo&aacute;n c&aacute;c n&acirc;ng cấp v&agrave; n&acirc;ng cao hiệu suất trong Galaxy A55, khiến n&oacute; trở th&agrave;nh một t&ugrave;y chọn hấp dẫn cho những người t&igrave;m kiếm sự c&acirc;n bằng giữa c&aacute;c t&iacute;nh năng v&agrave; khả năng t&agrave;i ch&iacute;nh.</p>', 'image5.png', 'sam-sung', 1, 'Rò rỉ Samsung Galaxy A55 chạy trên Exynos 1480 SoC', 1, 0),
(11, '2025-04-13 14:38:40.000000', 1, 'Apple chính thức khóa sign iOS 18.3.2, chặn người dùng hạ cấp', 'Apple thường khóa sign một phiên bản iOS cũ hơn sau khi phát hành bản cập nhật mới và quá trình này ngăn người dùng ‌iPhone‌ cài đặt các phiên bản iOS lỗi thời. \"Sign\" đề cập đến kiểm tra xác minh phía máy chủ được thực hiện khi các phiên bản iOS được tải xuống ‌iPhone‌. Chỉ phần mềm vượt qua kiểm tra xác minh của “Nhà Táo” mới có thể được cài đặt.\n\nViệc ngăn chặn việc hạ cấp đảm bảo rằng khách hàng có được những cải tiến bảo mật mới nhất và không dễ bị tấn công hoặc lỗ hổng bảo mật.\n\nĐược biết, bản cập nhật iOS 18.4 đã khắc phục hơn 60 lỗ hổng bảo mật nên bạn nên cài đặt phần mềm này trên iPhone của mình càng sớm càng tốt.', 'image6.png', 'Apple', 1, 'Apple chính thức khóa sign iOS 18.3.2, chặn người dùng hạ cấp', 1, 0),
(14, '2025-04-20 21:17:22.000000', 1, 'giảm giá cực sốc cho Đại lễ 30/4', 'giảm giá cực sốc cho Đại lễ 30/4', 'image7.png', 'khuyen-mai', 1, 'khuyến mãi', 6, 1);

